class WebGLManager{constructor(){this.effects={};this.canvases={};this.scenes={};this.initialized=false;this.performanceMode=this.detectPerformanceMode()}detectPerformanceMode(){if(!navigator.hardwareConcurrency||navigator.hardwareConcurrency<=2){return"low"}if(navigator.deviceMemory&&navigator.deviceMemory<=4){return"medium"}if(/mobile|android|iphone/i.test(navigator.userAgent)){return"medium"}return"high"}init(){if(this.initialized)return;const currentPage=this.detectCurrentPage();if(currentPage==="home"){this.initHomeParticles()}else if(currentPage==="journey"){this.initJourneyTimeline()}else if(currentPage==="creations"){this.initCreationsGallery()}else if(currentPage==="odyssey"){this.initOdysseyNarrative()}else if(currentPage==="connect"){this.initConnectNetwork()}this.initialized=true;console.log(`🎨 WebGL Manager initialized (${this.performanceMode} performance mode)`)}detectCurrentPage(){const path=window.location.pathname;const filename=path.split("/").pop()||"index.html";if(filename.includes("journey"))return"journey";if(filename.includes("creations"))return"creations";if(filename.includes("odyssey"))return"odyssey";if(filename.includes("connect"))return"connect";return"home"}initHomeParticles(){const container=document.querySelector('[data-webgl="home-particles"]');if(!container){const heroSection=document.querySelector(".hero-section");if(heroSection){const webglContainer=document.createElement("div");webglContainer.id="home-particles-webgl";webglContainer.style.cssText=`\n          position: absolute;\n          top: 0;\n          left: 0;\n          width: 100%;\n          height: 100%;\n          z-index: 1;\n          pointer-events: none;\n        `;heroSection.appendChild(webglContainer)}return}const canvas=document.createElement("canvas");canvas.width=window.innerWidth;canvas.height=window.innerHeight;container.appendChild(canvas);const ctx=canvas.getContext("2d");const particleCount=this.performanceMode==="high"?150:this.performanceMode==="medium"?80:40;const particles=Array.from({length:particleCount},()=>({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*2,vy:(Math.random()-.5)*2,size:Math.random()*3+1,hue:Math.random()*360}));const animate=()=>{ctx.clearRect(0,0,canvas.width,canvas.height);ctx.fillStyle="rgba(0, 0, 0, 0.05)";ctx.fillRect(0,0,canvas.width,canvas.height);particles.forEach((p,i)=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=canvas.width;if(p.x>canvas.width)p.x=0;if(p.y<0)p.y=canvas.height;if(p.y>canvas.height)p.y=0;ctx.fillStyle=`hsla(${p.hue}, 100%, 60%, 0.7)`;ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fill();for(let j=i+1;j<particles.length;j++){const p2=particles[j];const dx=p2.x-p.x;const dy=p2.y-p.y;const distance=Math.sqrt(dx*dx+dy*dy);if(distance<150){ctx.strokeStyle=`hsla(${p.hue}, 100%, 60%, ${.3*(1-distance/150)})`;ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(p2.x,p2.y);ctx.stroke()}}});requestAnimationFrame(animate)};animate();this.canvases.homeParticles=canvas}initJourneyTimeline(){if(!THREE)return;const container=document.querySelector('[data-webgl="journey-timeline"]');if(!container){const heroSection=document.querySelector(".hero-section");if(heroSection){const webglContainer=document.createElement("div");webglContainer.id="journey-timeline-webgl";webglContainer.style.cssText=`\n          position: absolute;\n          top: 0;\n          left: 0;\n          width: 100%;\n          height: 100%;\n          z-index: 1;\n        `;heroSection.appendChild(webglContainer)}return}const scene=new THREE.Scene;const camera=new THREE.PerspectiveCamera(75,window.innerWidth/window.innerHeight,.1,1e3);const renderer=new THREE.WebGLRenderer({antialias:true,alpha:true});renderer.setSize(window.innerWidth,window.innerHeight);renderer.setClearColor(0,.1);container.appendChild(renderer.domElement);camera.position.z=5;const curve=new THREE.LineCurve3(new THREE.Vector3(-10,0,0),new THREE.Vector3(10,0,0));const points=curve.getPoints(100);const modifiedPoints=points.map((p,i)=>{const wave=Math.sin(i*.1)*2;return new THREE.Vector3(p.x,wave,p.z)});const geometry=new THREE.BufferGeometry;geometry.setFromPoints(modifiedPoints);const material=new THREE.LineBasicMaterial({color:8150271,linewidth:3});const line=new THREE.Line(geometry,material);scene.add(line);for(let i=0;i<modifiedPoints.length;i+=20){const cubeGeom=new THREE.BoxGeometry(.2,.2,.2);const cubeMat=new THREE.MeshBasicMaterial({color:16739229});const cube=new THREE.Mesh(cubeGeom,cubeMat);cube.position.copy(modifiedPoints[i]);scene.add(cube)}const animate=()=>{requestAnimationFrame(animate);scene.rotation.x+=5e-4;scene.rotation.z+=3e-4;renderer.render(scene,camera)};animate();this.scenes.journeyTimeline={scene:scene,camera:camera,renderer:renderer};window.addEventListener("resize",()=>{camera.aspect=window.innerWidth/window.innerHeight;camera.updateProjectionMatrix();renderer.setSize(window.innerWidth,window.innerHeight)})}initCreationsGallery(){if(!THREE)return;const container=document.querySelector('[data-webgl="creations-gallery"]');if(!container)return;const canvas=document.createElement("canvas");canvas.width=window.innerWidth;canvas.height=window.innerHeight;container.appendChild(canvas);const ctx=canvas.getContext("2d");const particles=Array.from({length:50},()=>({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*1,vy:(Math.random()-.5)*1,size:Math.random()*2+1,color:`hsl(${Math.random()*360}, 100%, 60%)`}));const animate=()=>{ctx.fillStyle="rgba(0, 0, 0, 0.1)";ctx.fillRect(0,0,canvas.width,canvas.height);particles.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=canvas.width;if(p.x>canvas.width)p.x=0;if(p.y<0)p.y=canvas.height;if(p.y>canvas.height)p.y=0;ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,p.size,0,Math.PI*2);ctx.fill()});requestAnimationFrame(animate)};animate();this.canvases.creationsGallery=canvas}initOdysseyNarrative(){const container=document.querySelector('[data-webgl="odyssey-narrative"]');if(!container)return;const canvas=document.createElement("canvas");canvas.width=window.innerWidth;canvas.height=window.innerHeight;container.appendChild(canvas);const ctx=canvas.getContext("2d");const blobs=Array.from({length:5},()=>({x:Math.random()*canvas.width,y:Math.random()*canvas.height,vx:(Math.random()-.5)*.5,vy:(Math.random()-.5)*.5,size:Math.random()*200+100,hue:30+Math.random()*30,opacity:.1}));const animate=()=>{ctx.fillStyle="rgba(0, 0, 0, 0.02)";ctx.fillRect(0,0,canvas.width,canvas.height);blobs.forEach(blob=>{blob.x+=blob.vx;blob.y+=blob.vy;if(blob.x-blob.size<0||blob.x+blob.size>canvas.width)blob.vx*=-1;if(blob.y-blob.size<0||blob.y+blob.size>canvas.height)blob.vy*=-1;ctx.fillStyle=`hsla(${blob.hue}, 100%, 50%, ${blob.opacity})`;ctx.filter="blur(40px)";ctx.beginPath();ctx.arc(blob.x,blob.y,blob.size,0,Math.PI*2);ctx.fill();ctx.filter="none"});requestAnimationFrame(animate)};animate();this.canvases.odysseyNarrative=canvas}initConnectNetwork(){const container=document.querySelector('[data-webgl="connect-network"]');if(!container)return;const canvas=document.createElement("canvas");canvas.width=window.innerWidth;canvas.height=window.innerHeight;container.appendChild(canvas);const ctx=canvas.getContext("2d");const nodes=Array.from({length:12},(_,i)=>({x:Math.cos(i/6*Math.PI)*200+canvas.width/2,y:Math.sin(i/6*Math.PI)*200+canvas.height/2,vx:(Math.random()-.5)*.5,vy:(Math.random()-.5)*.5,size:10,color:`hsl(${Math.random()*60+180}, 100%, 60%)`}));const animate=()=>{ctx.fillStyle="rgba(0, 0, 0, 0.1)";ctx.fillRect(0,0,canvas.width,canvas.height);nodes.forEach((node,i)=>{node.x+=node.vx;node.y+=node.vy;node.vx+=(Math.random()-.5)*.02;node.vy+=(Math.random()-.5)*.02;if(node.x<0||node.x>canvas.width)node.vx*=-1;if(node.y<0||node.y>canvas.height)node.vy*=-1;for(let j=i+1;j<nodes.length;j++){const node2=nodes[j];const dx=node2.x-node.x;const dy=node2.y-node.y;const distance=Math.sqrt(dx*dx+dy*dy);if(distance<300){ctx.strokeStyle=`hsla(180, 100%, 60%, ${.2*(1-distance/300)})`;ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(node.x,node.y);ctx.lineTo(node2.x,node2.y);ctx.stroke()}}ctx.fillStyle=node.color;ctx.beginPath();ctx.arc(node.x,node.y,node.size,0,Math.PI*2);ctx.fill()});requestAnimationFrame(animate)};animate();this.canvases.connectNetwork=canvas}destroy(){Object.values(this.canvases).forEach(canvas=>{canvas.remove()});Object.values(this.scenes).forEach(scene=>{if(scene.renderer){scene.renderer.dispose();scene.renderer.domElement.remove()}});this.canvases={};this.scenes={}}}const webglManager=new WebGLManager;if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",()=>{setTimeout(()=>{webglManager.init()},100)})}else{setTimeout(()=>{webglManager.init()},100)}if(typeof module!=="undefined"&&module.exports){module.exports=WebGLManager}